// // This is a 32-bit wide, 1-to-2 demultiplexer. Output z selects between inputs a and b based on the control signal s; when s=0, z outputs the value of b, and when s=1, z outputs the value of a.
module top_module(a, b, s, z);input s;
input [31:0] a, b;
output [31:0] z;

assign z = s? b: a;

endmodule
